import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a CD?", a: "A CD, or certificate of deposit, is a savings product where money is deposited for a fixed term in exchange for a stated yield." },
  { q: "How do you calculate CD interest?", a: "CD interest is calculated from the deposit, APY or interest rate, term length, and compounding frequency." },
  { q: "What happens when a CD matures?", a: "At maturity, you can usually withdraw the balance, renew the CD, or move the funds into another account." },
  { q: "What is the penalty for early CD withdrawal?", a: "Early withdrawal penalties vary by bank and term, often equal to several months of interest." },
  { q: "Are CDs a good investment?", a: "CDs can be useful for predictable, insured savings, but they may earn less than riskier investments over long periods." },
];

const money = (v: number, d = 0) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function cdValue(deposit: number, apy: number, months: number, compounds = 12) {
  return deposit * Math.pow(1 + apy / 100 / compounds, compounds * (months / 12));
}

export default function CDCalculator() {
  useCurrencyVersion();
  const [deposit, setDeposit] = useState(10000);
  const [apy, setApy] = useState(4);
  const [months, setMonths] = useState(24);
  const [frequency, setFrequency] = useState(12);
  const result = useMemo(() => {
    const finalValue = cdValue(deposit, apy, months, frequency);
    const effectiveApy = (Math.pow(1 + apy / 100 / frequency, frequency) - 1) * 100;
    return { finalValue, interest: finalValue - deposit, effectiveApy };
  }, [deposit, apy, months, frequency]);
  const comparison = [1, 2, 3, 4, 5].map((r) => ({ rate: r, m6: cdValue(10000, r, 6), y1: cdValue(10000, r, 12), y2: cdValue(10000, r, 24), y5: cdValue(10000, r, 60) }));

  return (
    <>
      <SEOHead title="Free CD Calculator Online - Calculate Certificate of Deposit Returns Instantly | CalcHive" description="Free online CD calculator. Calculate certificate of deposit final value, total interest earned and effective APY for any deposit, rate and term instantly. 100% free, no signup required." canonical="/cd-calculator" keywords="free CD calculator, certificate of deposit calculator free online, CD interest calculator free, calculate CD returns free, best CD rates calculator free" category="Financial Calculators" breadcrumbName="Free CD Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free CD Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate certificate of deposit returns, interest earned, and effective APY.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Initial deposit</label><input type="number" value={deposit} onChange={(e) => setDeposit(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Annual percentage yield (%)</label><input type="number" value={apy} onChange={(e) => setApy(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">CD term in months</label><input type="number" value={months} onChange={(e) => setMonths(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Compounding frequency</label><select value={frequency} onChange={(e) => setFrequency(Number(e.target.value))} className={inputClass}><option value={1}>Annually</option><option value={4}>Quarterly</option><option value={12}>Monthly</option><option value={365}>Daily</option></select></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Final CD Value</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.finalValue)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest earned</p><p className="text-lg font-extrabold text-foreground">{money(result.interest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Effective APY</p><p className="text-lg font-extrabold text-foreground">{result.effectiveApy.toFixed(2)}%</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate CD Returns and Interest for Free</h2><p className="text-muted-foreground leading-relaxed">This certificate of deposit calculator compounds your deposit over the selected term and reports final value, interest earned, and effective yield.</p>
          <h2 className="text-2xl font-bold text-foreground">How CD Rates and Terms Affect Your Earnings</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">CD Returns on $10,000 at Different Rates and Terms</caption><thead className="bg-muted/60"><tr>{["APY Rate", "6 Months", "1 Year", "2 Years", "5 Years"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.rate}><td className="py-2.5 px-3 font-semibold">{row.rate}%</td><td className="py-2.5 px-3">{money(row.m6)}</td><td className="py-2.5 px-3">{money(row.y1)}</td><td className="py-2.5 px-3">{money(row.y2)}</td><td className="py-2.5 px-3">{money(row.y5)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Certificate of Deposit Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this CD interest calculator free to compare terms and rates before locking money into a certificate of deposit.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/cd-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


